CREATE TABLE IF NOT EXISTS buenas_practicas (id INT AUTO_INCREMENT PRIMARY KEY, titulo VARCHAR(500) NOT NULL, descripcion TEXT, categoria VARCHAR(100) DEFAULT 'general', archivo VARCHAR(500), estado TINYINT DEFAULT 1, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
